const update = $json;
let chatId, text = '';
let raw = update;
let callbackQueryId = null;
let callbackMessageId = null;
let isCallback = false;

if (update.message) {
  chatId = update.message.chat.id;
  text = update.message.text || '';
} else if (update.callback_query) {
  isCallback = true;
  callbackQueryId = update.callback_query.id;
  chatId = update.callback_query.message.chat.id;
  callbackMessageId = update.callback_query.message.message_id;
  text = update.callback_query.data || '';
}

return [{ json: { chatId, text, raw, isCallback, callbackQueryId, callbackMessageId } }];

const data = $getWorkflowStaticData('global');
const incomingText = String($json?.text || '').trim();
const isReloadCommand = incomingText.startsWith('/reload');
const hasCatalog = !!data.catalog && Object.keys(data.catalog).length > 0;
const hasVendedores = !!data.vendedores && Object.keys(data.vendedores).length > 0;
const memoryEmpty = !(hasCatalog && hasVendedores) || isReloadCommand;
return [{ json: { ...$json, memoryEmpty, shouldReload: isReloadCommand, isReloadCommand } }];

const toNum=(v)=>{const n=parseFloat(String(v??'').replace(/,/g,'').replace(/[^0-9.\-]/g,''));return Number.isFinite(n)?n:0};
const norm=(s)=>String(s??'').trim();
const normKey=(k)=>String(k||'').toLowerCase().trim().replace(/\s+/g,'').replace(/[_\-]/g,'');
const getVal=(obj,terms)=>{if(!obj)return undefined;const keys=Object.keys(obj);const map=new Map(keys.map(k=>[normKey(k),k]));for(const t of terms){const nk=normKey(t);if(map.has(nk)) return obj[map.get(nk)]}return undefined};

const maquinasRows=$items('Leer DB_Maquinas').map(i=>i.json);
const opcionesRows=$items('Leer DB_Opciones').map(i=>i.json);
const preciosRows=$items('Leer DB_Precios').map(i=>i.json);
const vendedoresRows=(()=>{try{return $items('Leer DB_Vendedores').map(i=>i.json)}catch(e){return []}})();
const logRows=(()=>{try{return $items('Leer Log_Cotizaciones').map(i=>i.json)}catch(e){return []}})();

const catalog={};
const priceLookup={};
for(const p of preciosRows){const modelo=getVal(p,['modelo','model','maquina']);const paso=getVal(p,['paso_id','step_id','paso']);const opcion=getVal(p,['opcion','opcion_valor','label']);if(!modelo||!paso||!opcion) continue; priceLookup[`${modelo}||${paso}||${opcion}`]=toNum(getVal(p,['precio','price','costo','extra']));}
for(const m of maquinasRows){const modelo=getVal(m,['modelo','model','id','maquina_id']);if(!modelo) continue;catalog[String(modelo)]={id:String(modelo),name:String(getVal(m,['nombre','name'])||modelo),basePrice:toNum(getVal(m,['precio_base','base_price','precio'])),steps:[]}}
for(const o of opcionesRows){const modelo=getVal(o,['modelo','model','maquina']);if(!modelo||!catalog[String(modelo)]) continue;const stepId=String(getVal(o,['paso_id','step_id','paso'])||'paso');let st=catalog[String(modelo)].steps.find(s=>s.id===stepId);if(!st){st={id:stepId,question:String(getVal(o,['pregunta','question'])||'Selecciona una opción'),options:[]};catalog[String(modelo)].steps.push(st)};const label=String(getVal(o,['opcion_label','label','opcion'])||'Opción');const value=String(getVal(o,['opcion_valor','value'])||label);const price=priceLookup[`${modelo}||${stepId}||${value}`] ?? toNum(getVal(o,['opcion_precio','precio','price']));st.options.push({label,value,price})}

const vendedores={};
for(const v of vendedoresRows){const usuario=norm(getVal(v,['usuario','user','username']));if(!usuario) continue;const activoRaw=String(getVal(v,['activo'])??'').toLowerCase();const activo=['true','1','si','sí','yes'].includes(activoRaw)||getVal(v,['activo'])===true;vendedores[usuario.toLowerCase()]={usuario,password:String(getVal(v,['password','contrasena'])||''),nombre_completo:String(getVal(v,['nombre_completo','nombre'])||usuario),email_vendedor:String(getVal(v,['email_vendedor','email'])||''),rol:String(getVal(v,['rol'])||'vendedor').toLowerCase(),activo};}

const staticData=$getWorkflowStaticData('global');
staticData.catalog=catalog;
staticData.vendedores=vendedores;
staticData.logCot=Array.isArray(logRows)?logRows:[];
staticData.cot=staticData.cot||{};
staticData.sessions=staticData.sessions||{};

return [{json:{...$json,catalogLoaded:true,vendedoresLoaded:Object.keys(vendedores).length,logLoaded:staticData.logCot.length}}];

const { chatId, text, raw, shouldReload: inReload, isCallback, callbackQueryId, callbackMessageId } = $json;
const staticData = $getWorkflowStaticData('global');
staticData.cot = staticData.cot || {};
staticData.sessions = staticData.sessions || {};
const incomingText = String(text || '').trim();
const lower = incomingText.toLowerCase();
const command = lower.split(' ')[0];
const now = Date.now();
const SESSION_MS = 8 * 60 * 60 * 1000;

const sess = staticData.sessions[chatId] || null;
const isSessionActive = !!(sess && sess.loginTimestamp && (now - Number(sess.loginTimestamp) < SESSION_MS));
if (sess && !isSessionActive) delete staticData.sessions[chatId];

let action = null;
if (command === '/logout') {
  action = 'LOGOUT';
} else if (command === '/reload') {
  action = 'RELOAD_DONE';
} else if (command.startsWith('/reporte') || command === '/mis_cotizaciones' || command.startsWith('/exportar_excel')) {
  action = isSessionActive ? 'REPORTES' : 'LOGIN_FLOW';
} else if (!isSessionActive) {
  action = 'LOGIN_FLOW';
} else if (raw?.message?.text && raw.message.text.startsWith('/start')) {
  staticData.cot[chatId] = staticData.cot[chatId] || {};
  action = 'START';
} else if (raw?.callback_query?.data) {
  const data = raw.callback_query.data;
  if (data === 'MENU|AVANZADA' || data === 'MODE|ADV' || data === 'MODE|FAST') {
    const current = staticData.cot[chatId] || {};
    current.mode = data === 'MODE|FAST' ? 'FAST' : 'ADV';
    staticData.cot[chatId] = current;
    action = 'MENU_SELECTION';
  } else {
    action = 'COTIZACION_FLOW';
  }
} else if (raw?.message?.text && !raw.message.text.startsWith('/')) {
  action = 'COTIZACION_FLOW';
} else {
  action = 'START';
}

return [{ json: { ...$json, action, shouldReload: !!inReload || command === '/reload', command, session: staticData.sessions[chatId] || null, isAuthenticated: !!staticData.sessions[chatId], isCallback, callbackQueryId, callbackMessageId } }];

const staticData = $getWorkflowStaticData('global');
const catalog = staticData.catalog || {};
const models = Object.keys(catalog);
if (models.length === 0) {
  return [{ json: { chatId: $json.chatId, text: '⚠️ La memoria está vacía. Por favor ejecuta /start para recargar.', reply_markup: {} } }];
}
const keyboard = [];
let row = [];
models.forEach((model, index) => {
  row.push({ text: model, callback_data: `${model}|START` });
  if (row.length === 2 || index === models.length - 1) { keyboard.push(row); row = []; }
});
return [{ json: { chatId: $json.chatId, text: '🏭 *Catálogo VC999 Disponible*\n\nSelecciona la máquina que deseas cotizar:', reply_markup: { inline_keyboard: keyboard } } }];

const staticData = $getWorkflowStaticData('global');
const catalog = staticData.catalog || {};
const basePriceIndex = staticData.basePriceIndex || {};
const priceIndex = staticData.priceIndex || {};
staticData.cot = staticData.cot || {};

const chatId = $json.chatId;
const text = String($json.text ?? '').trim();
const callbackMessageId = $json.callbackMessageId ?? null;
const callbackQueryId = $json.callbackQueryId ?? null;
const isCallback = !!$json.isCallback;

const money = (n) => Number(n || 0).toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 0 });
const formatPriceUSD = (n) => `$${money(n)}`;
const toNum = (v) => {
  const s = String(v ?? '').replace(/[^0-9.,\-]/g, '').replace(/,/g, '');
  const n = parseFloat(s);
  return Number.isFinite(n) ? n : 0;
};
const normText = (v) => String(v ?? '').trim().replace(/\s+/g, ' ');
const normModel = (v) => normText(v).toUpperCase();
const normStep = (v) => normText(v).toLowerCase();
const stripPrice = (s) => {
  const raw = String(s ?? '');
  return raw
    .replace(/\([^)]*\$[\s\d.,]+[^)]*\)/g, '')
    .replace(/\+?\$[\s\d.,]+(\s*USD)?/gi, '')
    .replace(/\s{2,}/g, ' ')
    .trim();
};
const normOption = (v) => stripPrice(normText(v)).toLowerCase();
const optionKey = (label, value) => `${stripPrice(normText(label)).toLowerCase()}|${stripPrice(normText(value ?? label)).toLowerCase()}`;
const priceKey = (modelo, paso, opcionValor) => `${normModel(modelo)}|${normStep(paso)}|${normOption(opcionValor)}`;
const resolvePriceFinal = (modelo, paso, opcionValor, fallback=0) => {
  const key = priceKey(modelo, paso, normOption(opcionValor));
  const p = priceIndex[key];
  return Number.isFinite(Number(p)) ? Number(p) : toNum(fallback);
};
const humanizeStepId = (stepId) => {
  const safe = String(stepId ?? '').trim();
  const withSpaces = safe.replace(/[_-]+/g, ' ').replace(/([a-z])([A-Z])/g, '$1 $2').trim();
  if (!withSpaces) return 'Paso';
  return withSpaces.split(' ').filter(Boolean).map((word) => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()).join(' ');
};

const resolveMode = (state) => (state?.mode || 'ADV').toUpperCase();
const sanitizeMachine = (value) => String(value ?? '').trim().replace(/\.docx$/i, '').toUpperCase();
const ensureRunId = (state) => {
  if (!state.runId) state.runId = `${Date.now()}_${chatId}`;
  return state.runId;
};
const formatSelections = (selections) => Array.isArray(selections) && selections.length > 0
  ? selections.map((sel) => {
      const stepLabel = humanizeStepId(sel.step ?? 'Paso');
      const priceText = toNum(sel.price) > 0 ? ` (+${formatPriceUSD(sel.price)} USD)` : ' (+$0 USD)';
      return `- ${stepLabel}: ${sel.value ?? 'N/A'}${priceText}`;
    })
  : ['- Sin opciones'];

const startFastDefaults = (userState, machine) => {
  const steps = Array.isArray(machine.steps) ? machine.steps : [];
  const selections = [];
  let totalPrice = toNum(userState.basePrice);
  steps.forEach((step, idx) => {
    const options = Array.isArray(step?.options) ? step.options : [];
    if (options.length === 0) return;
    const defaultOpt = options.find((opt) => String(opt.label ?? '').includes('(Default)')) || options[0];
    const selectedValue = defaultOpt.value ?? defaultOpt.label ?? 'NA';
    const chosenPrice = resolvePriceFinal(userState.machine, step?.id ?? `step_${idx + 1}`, selectedValue, defaultOpt.price);
    selections.push({ step: step?.id ?? `step_${idx + 1}`, value: stripPrice(selectedValue), price: chosenPrice });
    totalPrice += chosenPrice;
  });
  userState.selections = selections;
  userState.totalPrice = totalPrice;
  userState.stepIndex = steps.length;
  userState.stage = 'await_customer_name';
  return { text: '⚡️ *Modo Rápido activado*
Se seleccionaron las opciones por defecto. Escribe el *nombre del cliente*.', reply_markup: {} };
};

const output = (payload) => [{ json: { ...payload, chatId, callbackMessageId, callbackQueryId, isCallback } }];

if (!chatId) {
  return output({ text: '⚠️ Falta chatId. Revisa el nodo Normalize Telegram.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState: null });
}

let userState = staticData.cot[chatId] || null;
const isStartMachine = text.includes('|') && text.endsWith('|START');
const isBasePick = text.includes('|BP|');
const isOpt = text.includes('|OPT|');

if (isStartMachine) {
  const model = sanitizeMachine(text.split('|')[0]);
  const machine = catalog[model];
  if (!machine) return output({ text: '⚠️ Error: Máquina no encontrada. Ejecuta /start.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });

  const mode = resolveMode(userState);
  const listBasePrice = Number.isFinite(Number(basePriceIndex[model])) ? Number(basePriceIndex[model]) : toNum(machine.basePrice);
  const ses = (staticData.sessions||{})[chatId] || {};
  userState = { mode, stage: 'await_base_price_choice', machine: model, stepIndex: 0, selections: [], basePrice: listBasePrice, totalPrice: listBasePrice, customer: {}, advisor: ses.nombre_completo || '' };
  ensureRunId(userState);
  staticData.cot[chatId] = userState;

  return output({
    text: `Precio base actual: ${formatPriceUSD(listBasePrice)} USD. ¿Deseas cambiarlo?`,
    reply_markup: {
      inline_keyboard: [
        [{ text: `✅ Usar ${formatPriceUSD(listBasePrice)}`, callback_data: `${model}|BP|LIST` }],
        [{ text: '✏️ Cambiar precio', callback_data: `${model}|BP|MANUAL` }],
      ],
    },
    isFinished: true,
    isReadyToGenerate: false,
    quotePayload: null,
    userState,
  });
}

if (isBasePick) {
  const [rawModel, , action] = text.split('|');
  const model = sanitizeMachine(rawModel);
  const machine = catalog[model];
  if (!userState || !machine || userState.machine !== model) return output({ text: '⚠️ Sesión expirada o modelo no coincide. Ejecuta /start.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });

  if (action === 'MANUAL') {
    userState.stage = 'await_base_price_manual';
    staticData.cot[chatId] = userState;
    return output({ text: '✏️ Escribe el nuevo *PRECIO BASE* (ejemplo: 16995).', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  }

  userState.basePrice = Number.isFinite(Number(basePriceIndex[model])) ? Number(basePriceIndex[model]) : toNum(machine.basePrice);
  userState.totalPrice = toNum(userState.basePrice);
  userState.stage = 'config';
  staticData.cot[chatId] = userState;
  if (userState.mode === 'FAST') {
    const fastResp = startFastDefaults(userState, machine);
    staticData.cot[chatId] = userState;
    return output({ ...fastResp, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  }
}

if (!isCallback && userState?.stage === 'await_base_price_manual') {
  const manualPrice = toNum(text);
  if (manualPrice <= 0) {
    return output({ text: '⚠️ Precio inválido. Escribe un número mayor a 0.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  }
  userState.basePrice = manualPrice;
  userState.totalPrice = manualPrice;
  userState.stage = 'config';
  staticData.cot[chatId] = userState;
  const machine = catalog[userState.machine];
  if (userState.mode === 'FAST') {
    const fastResp = startFastDefaults(userState, machine);
    staticData.cot[chatId] = userState;
    return output({ ...fastResp, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  }
}

if (isOpt) {
  const [model, , stepIdRaw, valRaw, rawPrice] = text.split('|');
  const normalizedModel = sanitizeMachine(model);
  const stepId = normStep(stepIdRaw);
  const cleanVal = normOption(valRaw);
  const priceFinal = resolvePriceFinal(normalizedModel, stepId, cleanVal, rawPrice);
  if (!userState || userState.machine !== normalizedModel) return output({ text: '⚠️ Sesión expirada o modelo no coincide. Ejecuta /start.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  if (userState.mode === 'FAST') return output({ text: '⚡️ Estás en Modo Rápido. Las opciones ya fueron auto-seleccionadas. Envía el nombre del cliente.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  userState.selections.push({ step: stepId, value: cleanVal, price: priceFinal });
  userState.totalPrice = toNum(userState.totalPrice) + priceFinal;
  userState.stepIndex += 1;
}

if (!isCallback && userState) {
  const msg = normText(text);
  if (userState.stage === 'await_customer_name') {
    userState.customer.name = msg;
    userState.stage = 'await_customer_email';
    staticData.cot[chatId] = userState;
    return output({ text: '📝 Ahora escribe el *correo del cliente*:', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });
  }
  if (userState.stage === 'await_customer_email') {
    userState.customer.email = msg;
    const ses=(staticData.sessions||{})[chatId]||{};
    userState.advisor = ses.nombre_completo || userState.advisor || '';
    const log=Array.isArray(staticData.logCot)?staticData.logCot:[];
    const dup=log.filter(r=>String(r.maquina||'').toLowerCase()===String(userState.machine||'').toLowerCase() && String(r.cliente_email||'').toLowerCase()===String(userState.customer.email||'').toLowerCase() && String(r.vendedor_usuario||'').toLowerCase()===String((ses.usuario||'')).toLowerCase()).slice(-1)[0];
    if(dup && msg.toLowerCase()!=='crear nueva'){
      userState.stage='await_duplicate_decision'; userState.duplicateRow=dup; staticData.cot[chatId]=userState;
      return output({text:`⚠️ Ya cotizaste esta máquina para este cliente (folio ${dup.folio||''}). Responde *Editar* o *Nueva*.`,reply_markup:{},isFinished:true,isReadyToGenerate:false,quotePayload:null,userState});
    }
    userState.stage = 'done';
    const payload = {
      machine: sanitizeMachine(userState.machine),
      basePrice: toNum(userState.basePrice),
      totalPrice: toNum(userState.totalPrice),
      selections: userState.selections,
      customer: userState.customer,
      advisor: userState.advisor,
      runId: ensureRunId(userState),
    };
    userState.payloadFinal = payload;
    staticData.cot[chatId] = userState;
    const optionLines = formatSelections(userState.selections).join('
');
    const summaryText = `🛠️ *Cotización ${userState.machine}*
*Máquina:* ${userState.machine}
*Base:* ${formatPriceUSD(payload.basePrice)} USD
*Opciones:*
${optionLines}
*Total:* ${formatPriceUSD(payload.totalPrice)} USD
*Cliente:* ${userState.customer.name || 'N/A'}
*Correo:* ${userState.customer.email || 'N/A'}
*Asesor:* ${userState.advisor || 'N/A'}
✅ Confirmo datos. Procediendo a generar y enviar PDF.`;
    return output({ text: summaryText, reply_markup: {}, isFinished: true, isReadyToGenerate: true, quotePayload: payload, userState });
  }
}

if (!userState) return output({ text: 'Usa /start y selecciona una máquina para iniciar.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState: null });
const machineConfig = catalog[userState.machine];
if (!machineConfig) return output({ text: '⚠️ Catálogo no disponible. Ejecuta /start para recargar.', reply_markup: {}, isFinished: true, isReadyToGenerate: false, quotePayload: null, userState });

let response = {};
let isFinished = false;

if (userState.stage === 'config') {
  const currentIndex = userState.stepIndex;
  if (currentIndex < machineConfig.steps.length) {
    const step = machineConfig.steps[currentIndex];
    const stepOptions = Array.isArray(step.options) ? step.options : [];
    const inline_keyboard = [];
    const seenOptions = new Set();

    stepOptions.forEach((opt) => {
      const value = opt.value ?? opt.label ?? 'NA';
      const cleanValue = stripPrice(value);
      const key = optionKey(stripPrice(opt.label ?? value), cleanValue);
      if (seenOptions.has(key)) return;
      seenOptions.add(key);

      const baseText = stripPrice(opt.label ?? value);
      const priceFinal = resolvePriceFinal(userState.machine, step.id, cleanValue, opt.price);
      const isDefaultLike = /^default$/i.test(String(cleanValue || '').trim()) || /\(default\)/i.test(String(opt.label || ''));
      const buttonText = isDefaultLike
        ? `${baseText}`.trim()
        : (priceFinal > 0 ? `${baseText} (+${formatPriceUSD(priceFinal)})`.trim() : `${baseText}`.trim());

      inline_keyboard.push([{ text: buttonText, callback_data: `${userState.machine}|OPT|${normStep(step.id)}|${normOption(cleanValue)}|${priceFinal}` }]);
    });

    response = {
      text: `🛠️ *${userState.machine}* (Paso ${currentIndex + 1}/${machineConfig.steps.length})
💰 Total: ${formatPriceUSD(userState.totalPrice)} USD

Selecciona: *${step.question || humanizeStepId(step.id || `Paso ${currentIndex + 1}`)}*`,
      reply_markup: { inline_keyboard },
    };
  } else {
    userState.stage = 'await_customer_name';
    isFinished = true;
    response = { text: `✅ *Cotización lista*
Modelo: *${userState.machine}*
Total: *${formatPriceUSD(userState.totalPrice)} USD*

Escribe el *NOMBRE del Cliente*:`, reply_markup: {} };
  }
} else if (userState.stage === 'await_customer_name') {
  isFinished = true;
  response = { text: '📝 Ahora escribe el *NOMBRE del cliente*:', reply_markup: {} };
} else if (userState.stage === 'await_customer_email') {
  isFinished = true;
  response = { text: '📝 Ahora escribe el *correo del cliente*:', reply_markup: {} };
} else if (userState.stage === 'await_duplicate_decision') {
  isFinished = true;
  response = { text: '⚠️ Cotización duplicada detectada. Escribe *Editar* o *Nueva*.', reply_markup: {} };
} else if (userState.stage === 'done') {
  const payload = userState.payloadFinal || {
    machine: sanitizeMachine(userState.machine),
    basePrice: toNum(userState.basePrice),
    totalPrice: toNum(userState.totalPrice),
    selections: userState.selections,
    customer: userState.customer,
    advisor: userState.advisor || '',
    runId: ensureRunId(userState),
  };
  response = { text: '✅ Listo. Procediendo a generar y enviar PDF.', reply_markup: {}, quotePayload: payload, isReadyToGenerate: true };
  isFinished = true;
}

staticData.cot[chatId] = userState;
return output({
  text: response.text || '',
  reply_markup: response.reply_markup || {},
  isFinished: !!isFinished,
  isReadyToGenerate: !!response.quotePayload,
  quotePayload: response.quotePayload || null,
  userState,
});

const input = $items('¿Terminó?')[0]?.json ?? $json;
const userState = input.userState || {};
const customer = userState.customer || {};
const toNum = (v) => { const s = String(v ?? '').replace(/[^0-9.\-]/g, ''); const n = parseFloat(s); return Number.isFinite(n) ? n : 0; };
const sanitizeMachine = (value) => String(value ?? '').trim().replace(/\.docx$/i, '');

const machineRaw = userState.machine ?? input.quotePayload?.machine ?? '';
const machine = sanitizeMachine(machineRaw);
const basePrice = Number.isFinite(Number(userState.basePrice)) ? Number(userState.basePrice) : Number(input.quotePayload?.basePrice ?? 0);
const selections = Array.isArray(userState.selections)
  ? userState.selections.map((sel) => ({ step: sel.step ?? '', value: sel.value ?? '', price: toNum(sel.price) }))
  : [];
const selectionsTotal = selections.reduce((sum, sel) => sum + toNum(sel.price), 0);
const totalPrice = Number.isFinite(Number(userState.totalPrice)) ? Number(userState.totalPrice) : basePrice + selectionsTotal;
const runId = String(userState.runId ?? input.quotePayload?.runId ?? input.runId ?? `${Date.now()}_${input.chatId ?? 'chat'}`);

const payloadCanonical = {
  machine,
  basePrice,
  totalPrice,
  selections,
  customer: {
    name: customer.name ?? '',
    email: customer.email ?? '',
  },
  runId,
};

const fastapiBody = {
  ...payloadCanonical,
  modelo: payloadCanonical.machine,
  nombre_cliente: payloadCanonical.customer.name,
  email: payloadCanonical.customer.email,
  asesor: (input.session?.nombre_completo || userState.advisor || ''),
  precio_base: payloadCanonical.basePrice,
  precio_cambiado: payloadCanonical.totalPrice,
  selecciones: payloadCanonical.selections.map((s) => ({ paso: s.step, opcion: s.value, precio: s.price })),
};

return [{ json: { ...input, runId, fastapiBody } }];

